#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 1;

class KernelCa6k00378Custom {
public:
    __aicore__ inline KernelCa6k00378Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR mean, GM_ADDR var,
                                GM_ADDR weight, GM_ADDR bias, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t numChannels, uint32_t spatialPerBatch,
                                uint32_t batchSize, float eps)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        numChannels_ = numChannels;
        spatialPerBatch_ = spatialPerBatch;
        batchSize_ = batchSize;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
        meanGm_.SetGlobalBuffer((__gm__ float*)mean, numChannels_);
        varGm_.SetGlobalBuffer((__gm__ float*)var, numChannels_);
        weightGm_.SetGlobalBuffer((__gm__ float*)weight, numChannels_);
        biasGm_.SetGlobalBuffer((__gm__ float*)bias, numChannels_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(scalarQue_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t blockNum = AscendC::GetBlockNum();
        // Each block handles one channel
        if (blockIdx >= numChannels_) return;
        uint32_t c = blockIdx;

        // Preload per‑channel scalars into local variables
        float meanVal, varVal, weightVal, biasVal;
        {
            auto t = scalarQue_.AllocTensor<float>();
            AscendC::DataCopy(t, meanGm_[static_cast<int64_t>(c)], 1);
            meanVal = t(0);
            scalarQue_.FreeTensor(t);
        }
        {
            auto t = scalarQue_.AllocTensor<float>();
            AscendC::DataCopy(t, varGm_[static_cast<int64_t>(c)], 1);
            varVal = t(0);
            scalarQue_.FreeTensor(t);
        }
        {
            auto t = scalarQue_.AllocTensor<float>();
            AscendC::DataCopy(t, weightGm_[static_cast<int64_t>(c)], 1);
            weightVal = t(0);
            scalarQue_.FreeTensor(t);
        }
        {
            auto t = scalarQue_.AllocTensor<float>();
            AscendC::DataCopy(t, biasGm_[static_cast<int64_t>(c)], 1);
            biasVal = t(0);
            scalarQue_.FreeTensor(t);
        }

        float invStd = 1.0f / sqrt(varVal + eps_);

        // Process each batch element for this channel
        for (uint32_t b = 0; b < batchSize_; ++b) {
            int64_t base = static_cast<int64_t>((b * numChannels_ + c) * spatialPerBatch_);
            uint32_t remaining = spatialPerBatch_;
            uint32_t offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                auto xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base + offset], curLen);
                auto yLocal = outQueueY_.AllocTensor<float>();
                // y = ((x - mean) * invStd) * weight + bias
                AscendC::Adds(yLocal, xLocal, -meanVal, curLen);
                AscendC::Muls(yLocal, yLocal, invStd, curLen);
                AscendC::Muls(yLocal, yLocal, weightVal, curLen);
                AscendC::Adds(yLocal, yLocal, biasVal, curLen);
                AscendC::DataCopy(yGm_[base + offset], yLocal, curLen);
                inQueueX_.FreeTensor(xLocal);
                outQueueY_.FreeTensor(yLocal);
                offset += curLen;
                remaining -= curLen;
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> scalarQue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    AscendC::GlobalTensor<float> meanGm_;
    AscendC::GlobalTensor<float> varGm_;
    AscendC::GlobalTensor<float> weightGm_;
    AscendC::GlobalTensor<float> biasGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t numChannels_ {0};
    uint32_t spatialPerBatch_ {0};
    uint32_t batchSize_ {0};
    float eps_ {1e-05f};
};

extern "C" __global__ __aicore__ void ca6k00378_custom(GM_ADDR x, GM_ADDR mean, GM_ADDR var,
                                                        GM_ADDR weight, GM_ADDR bias, GM_ADDR y,
                                                        GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00378Custom op;
    op.Init(x, mean, var, weight, bias, y,
            tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.numChannels, tiling_data.spatialPerBatch,
            tiling_data.batchSize, tiling_data.eps);
    op.Process();
}
